1601	\begin{lemma}
1602	
1603	\leanok
1604	[$\Gamma$-collapse of the pushforward-congruence coherence]
1605	  \label{lem:gammaMap_pushforwardCongr_hom}
1606	  \lean{AlgebraicGeometry.gammaMap_pushforwardCongr_hom}
1607	  \uses{lem:gammaPushforwardIso}
1608	  Let \(f, g : X \to \operatorname{Spec} R\) be morphisms of schemes with \(f = g\), and \(M\)
1609	  an \(\mathcal{O}_X\)-module. Applying the global-sections functor \(\Gamma\) to the component
1610	  \((\mathrm{pushforwardCongr}\,(f = g))^{\mathrm{hom}}_M\) of the congruence coherence yields the
1611	  identity morphism on sections:
1612	  \[
1613	    \Gamma\bigl((\mathrm{pushforwardCongr}\,(f = g))^{\mathrm{hom}}_M\bigr)
1614	      = \operatorname{id}.
1615	  \]
1616	\end{lemma}
1617	\begin{proof}
1618	  \uses{lem:gammaPushforwardIso}
1619	  Substituting \(f = g\), the congruence coherence reduces to the identity morphism on sections.
1620	  The global-sections functor sends the identity to the identity. It carries no substantive
1621	  content.
1622	\end{proof}
